DROP TABLE IF EXISTS `workforce_payroll_readiness`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `workforce_payroll_readiness` (
  `readiness_id` int NOT NULL AUTO_INCREMENT,
  `payroll_period_id` int NOT NULL,
  `employee_id` int NOT NULL,
  `readiness_status` varchar(50) NOT NULL,
  `current_owner_role` varchar(50) NOT NULL,
  `supervisor_employee_id` int DEFAULT NULL,
  `supervisor_cleared_by_user_id` int DEFAULT NULL,
  `supervisor_cleared_at` datetime DEFAULT NULL,
  `hr_validated_by_user_id` int DEFAULT NULL,
  `hr_validated_at` datetime DEFAULT NULL,
  `hr_remarks` varchar(500) DEFAULT NULL,
  `finance_validated_by_user_id` int DEFAULT NULL,
  `finance_validated_at` datetime DEFAULT NULL,
  `finance_remarks` varchar(500) DEFAULT NULL,
  `returned_by_user_id` int DEFAULT NULL,
  `returned_to_role` varchar(50) DEFAULT NULL,
  `returned_at` datetime DEFAULT NULL,
  `return_reason` varchar(500) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`readiness_id`),
  UNIQUE KEY `uq_workforce_payroll_readiness_period_employee` (`payroll_period_id`,`employee_id`),
  KEY `idx_wpr_status` (`readiness_status`),
  KEY `idx_wpr_owner` (`current_owner_role`),
  KEY `idx_wpr_employee` (`employee_id`),
  KEY `idx_wpr_supervisor` (`supervisor_employee_id`),
  KEY `idx_wpr_supervisor_cleared_by_user` (`supervisor_cleared_by_user_id`),
  KEY `idx_wpr_hr_validated_by_user` (`hr_validated_by_user_id`),
  KEY `idx_wpr_finance_validated_by_user` (`finance_validated_by_user_id`),
  KEY `idx_wpr_returned_by_user` (`returned_by_user_id`),
  CONSTRAINT `fk_wpr_employee` FOREIGN KEY (`employee_id`) REFERENCES `employees` (`employee_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_wpr_finance_validated_by_user` FOREIGN KEY (`finance_validated_by_user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_wpr_hr_validated_by_user` FOREIGN KEY (`hr_validated_by_user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_wpr_period` FOREIGN KEY (`payroll_period_id`) REFERENCES `payroll_periods` (`period_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_wpr_returned_by_user` FOREIGN KEY (`returned_by_user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_wpr_supervisor_cleared_by_user` FOREIGN KEY (`supervisor_cleared_by_user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_wpr_supervisor_employee` FOREIGN KEY (`supervisor_employee_id`) REFERENCES `employees` (`employee_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3151 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

